import sys
sys.setrecursionlimit(10000)

def kosarajus_scc(n, adj):
    """
    adj: dict {u: [v, ...]} (directed)
    Returns list of SCCs (each a sorted list of nodes).
    """
    # Build transpose
    radj = {i: [] for i in range(n)}
    for u in adj:
        for v in adj[u]:
            radj[v].append(u)

    # Pass 1: DFS on original graph, push to stack on finish
    visited = [False] * n
    finish_stack = []

    def dfs1(u):
        visited[u] = True
        for v in adj.get(u, []):
            if not visited[v]:
                dfs1(v)
        finish_stack.append(u)  # push on FINISH

    for u in range(n):
        if not visited[u]:
            dfs1(u)

    # Pass 2: DFS on TRANSPOSE in reverse finish order
    visited2 = [False] * n
    sccs = []

    def dfs2(u, component):
        visited2[u] = True
        component.append(u)
        for v in ___________:   # use transposed graph
            if not visited2[v]:
                dfs2(v, component)

    while finish_stack:
        u = finish_stack.pop()
        if not visited2[u]:
            comp = []
            dfs2(u, comp)
            sccs.append(sorted(comp))
    return sccs
